dtsPropsFor.CodeHighlighter:
/** Source code to render, syntax-highlighted with the anyplot imprint theme. */
code: string;
/** anyplot language id: "python" | "r" | "julia" | "javascript". Defaults to "python"; unknown ids render as plain text. */
language?: string;
/** Library id — overrides the language's default grammar (e.g. "muix" highlights as React TSX). */
library?: string;

dtsPropsFor.ThemeToggle:
/** Current theme mode. */
mode: 'system' | 'light' | 'dark';
/** Advance to the next mode in the system → light → dark cycle. */
onCycle: () => void;

dtsPropsFor.SectionHeader:
/** Prefix symbol rendered at title size — e.g. "§", "❯", "$". */
prompt?: string;
/** Heading content; a string or rich nodes. An <em> child renders in brand green italic. */
title: React.ReactNode;
/** Trailing link label. Pair with `linkTo` (internal route) OR `linkHref` (external URL). */
linkText?: string;
/** Internal react-router route for the trailing link. Mutually exclusive with `linkHref`. */
linkTo?: string;
/** External URL for the trailing link (opens in a new tab). Mutually exclusive with `linkTo`. */
linkHref?: string;

dtsPropsFor.Footer:
/** Optional analytics callback fired on footer link clicks. */
onTrackEvent?: (name: string, props?: Record<string, string | undefined>) => void;
/** Currently-selected spec id, passed through to the "report an issue" link. */
selectedSpec?: string;
/** Currently-selected library id, passed through to the "report an issue" link. */
selectedLibrary?: string;
